// // This module implements a GPIO controller that produces an output signal (o) which is the logical AND of the inputs (i0 to i4).
module gpio_controller (
    input wire i0,
    input wire i1,
    input wire i2,
    input wire i3,
    input wire i4,
    output wire o
);
    assign o = i0 | i1 | i2 | i3 | i4;
endmodule
